          bcc_address_email_list: body.bcc_address_email_list || null,
        },
        sent: true,
      },
    },
  };
});

const items = $input.all();

return items.map((item) => {
  const input = item.json || {};
  const sc = input.send_classification || {};
  return {
    json: {
