return items.map(item => {
  const input = item.json || {};
  const det = input.deterministic || { flags: {}, operational_flags: {} };
  const classifier = input.classifier || {};
  const category = classifier.category;
  const confidence = typeof classifier.confidence === 'number' ? classifier.confidence : 0;
  const detFlags = det.flags || {};

  let plan;
  let effectiveCategory = category;
  let confidenceOverridden = false;
  let reason;

  if (det.noop_match === true) {
    plan = { ...NOOP_PLAN };
    effectiveCategory = null;
    reason = det.rule_id === 'op-duplicate'
      ? 'Operational rule op-duplicate matched: duplicate event, no further action.'
      : 'Operational rule op-self-sent matched: self-sent message, no further action.';
  } else if (det.rule_id === 'op-malformed') {
    plan = { ...BASE_PLANS.OTHER, stop_active_sequence: false, terminal_status: 'REJECTED' };
    effectiveCategory = 'OTHER';
    reason = 'Payload failed validation in Workflow 1 (op-malformed) - routed to REJECTED for review.';
  } else if (det.rule_id === 'op-unsupported-event') {
    plan = { ...BASE_PLANS.OTHER, stop_active_sequence: false, human_review_required: false, terminal_status: 'COMPLETED_NO_SEND' };
    effectiveCategory = 'OTHER';
    reason = 'Event type is not supported for reply processing (op-unsupported-event) - no action required.';
  } else {
    if (category !== null && confidence < 0.60) {
      effectiveCategory = 'AMBIGUOUS';
      confidenceOverridden = true;
    }
    const base = BASE_PLANS[effectiveCategory] || BASE_PLANS.AMBIGUOUS;
    plan = { ...base };

    if (effectiveCategory === 'LEGAL_PRIVACY_OR_COMPLAINT') {
      plan.legal_review_required = !!(detFlags['det-legal-001'] || detFlags['det-legal-002'] || detFlags['det-regulator-001']);
      plan.privacy_review_required = !!detFlags['det-legal-001'];
      plan.reputational_review_required = !!(detFlags['det-regulator-001'] || detFlags['det-complaint-001']);
      plan.durable_dnc_intent = !!detFlags['det-legal-001'];
      plan.address_suppression_intent = plan.durable_dnc_intent ? 'ORGANISATION_DNC' : 'REVIEW_HOLD';
    }

    if (effectiveCategory === 'HOSTILE_OR_REPUTATIONAL_RISK') {
      plan.legal_review_required = !!detFlags['det-hostile-001'];
      plan.address_suppression_intent = detFlags['det-hostile-001'] ? 'GLOBAL_BLOCKLIST' : 'ORGANISATION_DNC';
    }

    if (det.media_flag === true) {
      plan.reputational_review_required = true;
      plan.human_review_required = true;
    }

    if (confidenceOverridden) {
      reason = `Classifier confidence ${confidence} for ${category} is below the 0.60 threshold - overridden to AMBIGUOUS per policy-HMZ-1.2 Section 4.`;
    } else if (det.deterministic_match === true) {
      reason = `Deterministic rule ${det.rule_id} matched category ${effectiveCategory}.`;
    } else {
      reason = `Mock classifier matched category ${effectiveCategory} with confidence ${confidence}.`;
    }
  }

  let interestStage = classifier.interest_stage || 'UNKNOWN';
  if (interestStage === 'ALPHA_INTEREST') {
    interestStage = 'VALIDATION_SPRINT_INTEREST';
  }

  const extra = plan.extra || {};
  const { extra: _omit, ...planFields } = plan;

  const decision = {
    category: effectiveCategory,
    confidence,
    confidence_overridden: confidenceOverridden,
    ...planFields,
    ...extra,
    interest_stage: interestStage,
    reason
  };

  return {
    json: {
      ...input,
      decision
    }
  };
});

