    if (!Object.prototype.hasOwnProperty.call(decision, field)) {
      errors.push(`decision.${field} is missing`);
    }
  }

  if (decision.category !== null && !ALLOWED_CATEGORIES.includes(decision.category)) {
    errors.push(`decision.category "${decision.category}" is not an allowed category`);
  }

  if (typeof decision.confidence !== 'number' || decision.confidence < 0 || decision.confidence > 1) {
    errors.push(`decision.confidence "${decision.confidence}" is not a number between 0 and 1`);
  }

  for (const field of BOOLEAN_DECISION_FIELDS) {
    if (Object.prototype.hasOwnProperty.call(decision, field) && typeof decision[field] !== 'boolean') {
      errors.push(`decision.${field} must be true or false, got ${JSON.stringify(decision[field])}`);
    }
  }
  for (const field of OPTIONAL_BOOLEAN_DECISION_FIELDS) {
    if (Object.prototype.hasOwnProperty.call(decision, field) && typeof decision[field] !== 'boolean') {
      errors.push(`decision.${field} must be true or false, got ${JSON.stringify(decision[field])}`);
    }
  }

  for (const field of VALIDATION_LEARNING_TRISTATE_FIELDS) {
    if (Object.prototype.hasOwnProperty.call(validationLearning, field) && !isTriState(validationLearning[field])) {
      errors.push(`validation_learning.${field} must be true, false, or "unknown", got ${JSON.stringify(validationLearning[field])}`);
    }
  }

  if (!ALLOWED_SUPPRESSION_INTENTS.includes(decision.address_suppression_intent)) {
    errors.push(`decision.address_suppression_intent "${decision.address_suppression_intent}" is not an allowed suppression intent`);
  }

  if (Object.prototype.hasOwnProperty.call(decision, 'interest_status_update') &&
      !ALLOWED_INTEREST_STATUS_UPDATES.includes(decision.interest_status_update)) {
    errors.push(`decision.interest_status_update "${decision.interest_status_update}" is not an allowed value`);
  }

  if (!ALLOWED_INTEREST_STAGES.includes(decision.interest_stage)) {
    errors.push(`decision.interest_stage "${decision.interest_stage}" is not an allowed value`);
  }
  if (decision.interest_stage === 'ALPHA_INTEREST') {
    errors.push('decision.interest_stage is ALPHA_INTEREST; this must never be set automatically (policy-HMZ-1.2)');
  }

  if (!ALLOWED_EXTERNAL_ACTION_STATUSES.includes(decision.external_action_status)) {
    errors.push(`decision.external_action_status "${decision.external_action_status}" implies a real external action; only NOT_PERFORMED or NOOP are allowed in Phase 3`);
  }

  if (!ALLOWED_TERMINAL_STATUSES.includes(decision.terminal_status)) {
    errors.push(`decision.terminal_status "${decision.terminal_status}" is not an allowed terminal status`);
  }
  if (!ALLOWED_DRAFT_STATUSES.includes(decision.reply_draft_status)) {
    errors.push(`decision.reply_draft_status "${decision.reply_draft_status}" is not an allowed draft status`);
  }
  if (Object.prototype.hasOwnProperty.call(draft, 'draft_status') &&
      !ALLOWED_DRAFT_STATUSES.includes(draft.draft_status)) {
    errors.push(`draft.draft_status "${draft.draft_status}" is not an allowed draft status`);
  }

  if (typeof draft.draft_text === 'string') {
    for (const entry of PROHIBITED_CLAIM_PATTERNS) {
      if (entry.pattern.test(draft.draft_text)) {
        errors.push(`draft.draft_text appears to contain a ${entry.label}`);
      }
    }
  }

  if (nes.operating_mode === 'VALIDATION' && decision.reply_permitted === true && decision.human_review_required !== true) {
    errors.push('decision.reply_permitted is true but human_review_required is not true under OPERATING_MODE=VALIDATION');
  }

  const valid = errors.length === 0;
  let finalDecision = decision;

  if (!valid) {
    finalDecision = {
      ...decision,
      review_hold: true,
      human_review_required: true,
      reply_permitted: false,
      external_action_status: 'NOT_PERFORMED',
      terminal_status: 'REVIEW_HOLD',
      reason: `Output validation failed (${errors.length} issue(s)) - routed to REVIEW_HOLD. Original reason: ${decision.reason || 'none'}`
    };
  }

  return {
    json: {
      ...input,
      decision: finalDecision,
      validation: {
        valid,
        errors,
        checked_at: new Date().toISOString()
      },
      validation_learning: validationLearning
    }
  };
});

