  let decisionPath;

  const replyLanguage = String(reply.language || '').toLowerCase();
  const isEnglishLanguage = !replyLanguage || replyLanguage === 'en' || replyLanguage === 'eng' || replyLanguage.startsWith('en-');

  if (det.noop_match === true) {
    result = { category: null, confidence: 1, evidence: [`operational rule ${det.rule_id} matched - no classification needed`] };
    decisionPath = 'OPERATIONAL_NOOP';
  } else if (det.deterministic_match === true) {
    result = { category: det.category, confidence: 1, evidence: [`deterministic rule ${det.rule_id} matched`] };
    decisionPath = 'DETERMINISTIC_RULE';
  } else if (!isEnglishLanguage) {
    result = {
      category: 'AMBIGUOUS',
      confidence: 0.3,
      evidence: [`non-English reply (language=${replyLanguage || 'unknown'}) routed to AMBIGUOUS per policy-HMZ-1.2 section 15`]
    };
    decisionPath = 'NON_ENGLISH_FALLBACK_T15';
  } else {
    result = deterministicHeuristicClassify(combined);
    decisionPath = 'DETERMINISTIC_HEURISTIC_CLASSIFIER';
  }

  let category = result.category;

// HMZ_BEHAVIOUR_FIX_V7:
// A how-it-works / more-info reply must not be treated as pricing unless actual
// commercial terms are present. This protects replies such as:
// "Yes, this is interesting. How would it work?"
const commercialTermsPresent = /\b(price|pricing|cost|quote|rfp|rfi|contract|msa|sow|discount|enterprise pricing|payment|pay|paid|invoice|fee|fees|budget)\b/.test(combined);
const infoIntentPresent =
  /\b(how (does|would|will|do|can) (this|it|you|we)|how would it work|how does it work|tell me more|more info|more information|can you explain|what is this|what does this do|how it works)\b/.test(combined)
  || (String(text || '').includes('?') && !commercialTermsPresent);

if (category === 'PRICING_OR_COMMERCIAL_NEGOTIATION' && !commercialTermsPresent && infoIntentPresent) {
  category = 'INFORMATION_REQUEST';
  result.category = 'INFORMATION_REQUEST';
  result.confidence = Math.max(typeof result.confidence === 'number' ? result.confidence : 0, 0.82);
  result.evidence = [
    ...(Array.isArray(result.evidence) ? result.evidence : []),
    'HMZ behaviour fix v7: information/how-it-works intent without commercial terms'
  ];
}

  const decisionTrace = {
    path: decisionPath,
    rule_id: det.rule_id || null,
    language: replyLanguage || 'unknown',
    classifier_version: 'deterministic-heuristic-1.0-v8',
    policy_version: nes.policy_version || 'policy-HMZ-1.2'
  };

  const classifier = {
    ...classifierInputs,
    category,
    confidence: result.confidence,
    evidence: result.evidence,
    classifier_version: 'deterministic-heuristic-1.0-v8',
    decision_trace: decisionTrace,
    detected_questions: category === 'INFORMATION_REQUEST' ? extractQuestions(text) : [],
    requested_action: category ? requestedActionFor(category) : 'NONE',
    risk_flags: category ? riskFlagsFor(category, det) : (det.media_flag ? ['media'] : []),
    permitted_automation_action: det.noop_match ? 'NOOP' : (category ? permittedAutomationFor(category) : 'NONE'),
    interest_stage: category ? interestStageFor(category) : 'UNKNOWN',
    validation_learning: emptyValidationLearning(nes)
  };

  if (classifier.validation_learning.voice_of_customer_excerpt == null && combined.trim().length > 0) {
    const excerptSource = text.trim().length > 0 ? text.trim() : subject.trim();
    classifier.validation_learning.voice_of_customer_excerpt = excerptSource.length > 240 ? excerptSource.slice(0, 240) + '...' : excerptSource;
  }

  if (category === 'PRICING_OR_COMMERCIAL_NEGOTIATION' && classifier.validation_learning.pricing_interest === 'unknown') {
    classifier.validation_learning.pricing_interest = true;
  }

  return {
    json: {
      ...input,
      classifier
    }
  };
});

